// n8n Code node (Node v2) — processes each incoming item and returns [{ json: ... }]
const items = $input.all();
const out = [];

// ---------- Helpers ----------
function isStrictCodeToken(tok){
  // Exactly 8 alphanum, at least 1 letter AND 1 digit
  return /^(?=[A-Za-z0-9]{8}$)(?=.*[A-Za-z])(?=.*\d)[A-Za-z0-9]{8}$/.test(tok);
}
function findStrictCodeAnywhere(s){
  const tokens = s.match(/[A-Za-z0-9]{4,}/g) || [];
  return tokens.some(isStrictCodeToken);
}
function extractStrictCode(s){
  const tokens = s.match(/[A-Za-z0-9]{6,}/g) || [];
  for (const t of tokens) if (isStrictCodeToken(t)) return t;
  return "";
}
function hasPostalCode(s){ return /\b\d{6}\b/.test(s); } // kept as-is
function hasVowel(s){ return /[aeiou]/i.test(s); }
function isGibberish(s){
  if (/^([a-z])\1{2,}$/i.test(s)) return true;
  if (/^(qwerty|asdfgh|zxcvb)$/i.test(s)) return true;
  return false;
}
const junkSingles = new Set([
  'test','testing','demo','sample','name','fullname','yourname',
  'abcd','abcde','xyz','qwerty','asdf','asdfg','lorem'
]);
function looksLikeSingleHumanName(s){
  if (!/^[A-Za-z.'\-]{3,}$/.test(s)) return false;
  if (!hasVowel(s)) return false;
  if (junkSingles.has(s.toLowerCase())) return false;
  if (isGibberish(s)) return false;
  return true;
}

const smallTalk = new Set([
  'hi','hello','hey','yo','ok','okay','k','thanks','thank you','tnx','👍','👌'
]);

for (const item of items) {
  const data = item.json || {};

  // Only process items that actually contain WhatsApp message payload
  const msgObj = data.messages?.[0];
  const waId = data.contacts?.[0]?.wa_id || '';
  const from = msgObj?.from || '';

  if (!msgObj || !waId || from !== waId) {
    // Not a real inbound user message — skip
    continue;
  }

  // Pull body from multiple WhatsApp shapes
  const body =
    msgObj.text?.body ||
    msgObj.button?.text ||
    msgObj.interactive?.button_reply?.title ||
    msgObj.interactive?.list_reply?.title ||
    msgObj.image?.caption ||
    '';

  const text = String(body || '').trim();
  if (!text) continue;

  const lower = text.toLowerCase().trim();
  if (smallTalk.has(lower)) continue;

  // ---------- Relevance rules ----------
  const parts = text.split(/[\r\n,;|]+/).map(s => s.trim()).filter(Boolean);
  const alphaParts = parts.filter(p => /[A-Za-z]/.test(p));

  const alphaWords = text.split(/\s+/).filter(w => /[A-Za-z]{2,}/.test(w));
  const wordish = (text.match(/[A-Za-z]{2,}/g) || []);
  const alphaCharCount = wordish.join('').length;

  const hasStrictCode = findStrictCodeAnywhere(text);
  const relevantByPostal = hasPostalCode(text) && alphaParts.length >= 1;
  const relevantByNameCity = (alphaWords.length >= 2 && alphaCharCount >= 6);

  let relevantBySingleName = false;
  if (!hasStrictCode && alphaParts.length === 1 && !hasPostalCode(text)) {
    const tok = alphaParts[0];
    if (parts.length === 1 && /^[A-Za-z.'\- ]+$/.test(tok)) {
      const singleWord = tok.trim().split(/\s+/).length === 1;
      if (singleWord && looksLikeSingleHumanName(tok)) {
        relevantBySingleName = true;
      }
    }
  }

  const isPureDigits = /^\d+$/.test(text);
  const isShortPureDigits = isPureDigits && text.length < 6;
  const isRelevant = hasStrictCode || relevantByPostal || relevantByNameCity || relevantBySingleName;
  if (!isRelevant || isShortPureDigits) continue;

  // ---------- Light parsing (optional, fills your fields if lines are Name / City / Code) ----------
  let fullName = "";
  let stateCity = "";
  let code = extractStrictCode(text);

  // Heuristic: first non-empty line with letters = name; second = city
  // If last line is the 8-char code, keep it; otherwise leave blank
  if (parts.length >= 1) {
    // Find first line that looks like a name
    const nameLine = parts.find(p => /^[A-Za-z .'\-]{3,}$/.test(p));
    if (nameLine) fullName = nameLine;
  }
  if (parts.length >= 2) {
    // Choose a different line than name that looks like a location
    const cityLine = parts.find(p => p !== fullName && /[A-Za-z]{2,}/.test(p));
    if (cityLine) stateCity = cityLine;
  }
  // If last trimmed part is exactly the code, prefer that
  const tail = parts[parts.length - 1] || "";
  if (isStrictCodeToken(tail)) code = tail;

  out.push({
    json: {
      senderWaId: waId,
      text,
      fullName,
      stateCity,
      code,
    }
  });
}

// Return array of { json: ... }
return out;

// n8n Code node (JavaScript)
// Parses AI output + user's latest message to produce a stable, casing-safe form state.

function safeParseJSON(s) {
  if (!s || typeof s !== 'string') return null;
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}

// --- Helpers & reference lists ---
const NIGERIAN_STATES = new Set([
  "abia","adamawa","akwa ibom","anambra","bauchi","bayelsa","benue","borno","cross river",
  "delta","ebonyi","edo","ekiti","enugu","gombe","imo","jigawa","kaduna","kano","katsina",
  "kebbi","kogi","kwara","lagos","nasarawa","niger","ogun","ondo","osun","oyo","plateau",
  "rivers","sokoto","taraba","yobe","zamfara","fct","f.c.t","abuja"
]);

function norm(s){ return s.trim().toLowerCase().replace(/\s+/g,' '); }

// Code must be exactly 8 chars, alphanumeric, with at least 1 letter and 1 digit
function isStrictCode(s){
  return /^(?=[A-Za-z0-9]{8}$)(?=.*[A-Za-z])(?=.*\d)[A-Za-z0-9]{8}$/.test(s || '');
}

// Tokenize a free text into candidate chunks (preserve original casing)
function splitParts(text) {
  if (!text) return [];
  // Split on commas, newlines, semicolons, pipes, and multiple spaces; keep words with letters/digits
  const raw = text
    .split(/[\n,;|]+/g)
    .map(s => s.trim())
    .filter(s => s.length > 0);
  // Also split long lines by multiple spaces but keep multi-word cities intact later
  // We'll keep both original chunks and further space-split tokens as needed.
  // For our heuristics, we'll first try the raw chunks, then fallback to finer splits.
  return raw;
}

// Heuristic: does this look like a location?
function looksLikeLocation(s){
  const t = norm(s);
  if (t.includes(',')) return true;                        // "Rivers, Port Harcourt"
  if (NIGERIAN_STATES.has(t)) return true;                 // "rivers", "lagos"
  const wordCount = t.split(' ').length;
  if (wordCount >= 2) return true;                         // "port harcourt", "ikeja lagos"
  return false;                                            // single unknown word → maybe name
}

// Heuristic: does this look like a person name (accept single word too)?
function looksLikeName(s){
  const t = s.trim();
  if (isStrictCode(t)) return false;
  // Allow letters, spaces, apostrophes, hyphens, dots; at least 2 chars
  return /^[A-Za-z.'\-\s]{2,}$/.test(t);
}

function extractBestFromText(text, form) {
  // Goal: fill only missing fields (do not overwrite valid existing values)
  if (!text || !(text = text.trim())) return;

  // Detect any 8-char code anywhere in the message
  // Preserve original casing of other fields; code is case-insensitive but we keep as typed.
  const codeMatch = text.match(/[A-Za-z0-9]{8}/g);
  if (!form.code && codeMatch) {
    // Choose the first token that passes strict check
    const found = codeMatch.find(tok => isStrictCode(tok));
    if (found) form.code = found;
  }

  // Split into candidate alpha chunks (exclude strict code tokens)
  const rawChunks = splitParts(text);
  const alphaChunks = rawChunks.filter(s => !isStrictCode(s));

  if (alphaChunks.length === 0) return;

  // If exactly one alpha chunk arrives, fill the missing field first.
  if (alphaChunks.length === 1) {
    const tok = alphaChunks[0];

    if (!form.fullName && form.stateCity) {
      // Have location, likely name
      if (looksLikeName(tok)) form.fullName = tok.trim();
      return;
    }
    if (!form.stateCity && form.fullName) {
      // Have name, leftover becomes location (even single-word like "Kano")
      form.stateCity = tok.trim();
      return;
    }
    // Both missing → classify
    if (!form.stateCity && looksLikeLocation(tok)) {
      form.stateCity = tok.trim();
      return;
    }
    if (!form.fullName && looksLikeName(tok)) {
      form.fullName = tok.trim();
      return;
    }
    // If still undecided, prefer name for single-word
    if (!form.fullName) form.fullName = tok.trim();
    return;
  }

  // If 2+ alpha chunks: pick best fits without overwriting known values
  if (alphaChunks.length >= 2) {
    // Prefer assigning a location first (comma or multi-word or state match)
    for (const s of alphaChunks) {
      if (!form.stateCity && looksLikeLocation(s)) {
        form.stateCity = s.trim();
        break;
      }
    }

    // Then use the longest remaining token as name if missing
    if (!form.fullName) {
      const candidates = alphaChunks.filter(s => s.trim() !== form.stateCity);
      const nameTok = candidates.sort((a,b)=>b.length-a.length)[0];
      if (nameTok && looksLikeName(nameTok)) {
        form.fullName = nameTok.trim();
      } else if (nameTok) {
        // Fallback: still use it as name to avoid stalling
        form.fullName = nameTok.trim();
      }
    }
  }
}

function computeMissing(form) {
  const missing = [];
  if (!form.fullName || !looksLikeName(form.fullName)) missing.push('Full Name');
  if (!form.stateCity || form.stateCity.trim().length < 2) missing.push('State & City');
  if (!form.code || !isStrictCode(form.code)) missing.push('Scratch Card Code');
  return missing;
}

function buildReply(missing) {
  // Short, 2-line prompts to avoid loops
  if (missing.length === 1 && missing[0] === 'Scratch Card Code') {
    return "Please send your 8-character alphanumeric Scratch Card Code (e.g., AB12CD34).\n\n(Type 'RESET' to start over.)";
  }
  if (missing.length === 1 && missing[0] === 'Full Name') {
    return "Please send your Full Name.\n\n(Type 'RESET' to start over.)";
  }
  if (missing.length === 1 && missing[0] === 'State & City') {
    return "Please send your State & City (e.g., Rivers, Port Harcourt).\n\n(Type 'RESET' to start over.)";
  }
  // Multiple fields missing
  return "Please send your Full Name, State & City (e.g., Rivers, Port Harcourt), and your 8-character alphanumeric Scratch Card Code (e.g., AB12CD34).\n\n(Type 'RESET' to start over.)";
}

const results = [];

for (const item of items) {
  const senderWaId = item.json.senderWaId || item.json.sender || item.json.from || '';
  const rawOutput = item.json.output;
  const userText = item.json.text || item.json.message || '';

  // Start with AI output if present
  const ai = safeParseJSON(rawOutput) || {};
  const form = {
    fullName: ai['Full Name'] ? String(ai['Full Name']).trim() : '',
    stateCity: ai['State & City'] ? String(ai['State & City']).trim() : '',
    code: ai['Scratch Card Code'] ? String(ai['Scratch Card Code']).trim() : '',
  };

  // Keep previously valid values; only clear code if it exists and fails strict validation
  if (form.fullName) form.fullName = form.fullName.trim();
  if (form.stateCity) form.stateCity = form.stateCity.trim();
  if (form.code && !isStrictCode(form.code)) form.code = '';

  // Merge in any new info from the latest free text (fills only missing fields, preserves casing)
  extractBestFromText(userText, form);

  // Final validation & completeness
  const missing = computeMissing(form);
  const ready = missing.length === 0;

  let reply = '';
  if (!ready) {
    reply = buildReply(missing);
  }

  results.push({
    json: {
      senderWaId,
      reply,
      ready,
      fullName: form.fullName || '',
      stateCity: form.stateCity || '',
      code: form.code || '',
    }
  });
}

return results;

// Input fields expected here:
// - senderWaId (string)
// - fullName, stateCity, code (strings)
// - prevTimestamps (array of "dd-MM-yyyy HH:mm:ss" strings in IST), may be undefined

const waid = String($json.Contact || '');
const prev = Array.isArray($json.prevTimestamps) ? $json.prevTimestamps : [];

// Parse "dd-MM-yyyy HH:mm:ss" as IST (+05:30)
function parseIST(ts) {
  if (!ts || typeof ts !== 'string') return null;
  const [datePart, timePart] = ts.trim().split(' ');
  if (!datePart || !timePart) return null;
  const [dd, MM, yyyy] = datePart.split('-').map(n => parseInt(n, 10));
  const [HH, mm, ss] = timePart.split(':').map(n => parseInt(n, 10));
  if (!yyyy || !MM || !dd) return null;
  const iso = `${yyyy}-${String(MM).padStart(2,'0')}-${String(dd).padStart(2,'0')}T${String(HH||0).padStart(2,'0')}:${String(mm||0).padStart(2,'0')}:${String(ss||0).padStart(2,'0')}+05:30`;
  const d = new Date(iso);
  return isNaN(d.getTime()) ? null : d;
}

const now = new Date();                          // UTC now
const boundary = new Date(now.getTime() - 15*24*60*60*1000); // 15 days ago (UTC)

// Scan previous timestamps; track newest
let recent = false;
let newest = null;

for (const ts of prev) {
  const d = parseIST(ts);
  if (!d) continue;
  if (!newest || d > newest) newest = d;
  if (d >= boundary) recent = true;
}

// Helper to format IST for the message
function fmtIST(d) {
  if (!d) return '';
  // add +05:30 offset to display as IST
  const ms = d.getTime() + (5.5 * 60 * 60 * 1000);
  const ist = new Date(ms);
  const pad = (n) => String(n).padStart(2,'0');
  const yyyy = ist.getUTCFullYear();
  const MM   = pad(ist.getUTCMonth()+1);
  const dd   = pad(ist.getUTCDate());
  const HH   = pad(ist.getUTCHours());
  const mm   = pad(ist.getUTCMinutes());
  const ss   = pad(ist.getUTCSeconds());
  return `${dd}-${MM}-${yyyy} ${HH}:${mm}:${ss}`;
}

if (recent) {
  // Block the append; tell user
  return {
    block: true,
    senderWaId: waid,
    reply: `⚠️ You are already registered.\nLast registration: ${fmtIST(newest)}.\nPlease try again after 15 days.`
  };
}

// Not recent → allow append; pass through your fields for Sheets + success message later
return {
  block: false,
  senderWaId: waid,
  fullName: $json.fullName || '',
  stateCity: $json.stateCity || '',
  code: $json.code || ''
};

